import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"介紹: 本地 AI 閘道 | Antigravity Manager","description":"了解 Antigravity Manager 的核心定位。它提供桌面端和本地 HTTP 閘道，支援多協議端點和帳號池排程，幫助你快速上手本地反代並避免常見設定錯誤。","frontmatter":{"title":"介紹: 本地 AI 閘道 | Antigravity Manager","sidebarTitle":"什麼是本地 AI 閘道","subtitle":"Antigravity Tools 是什麼：把「帳號 + 協議」做成本地 AI 閘道","description":"了解 Antigravity Manager 的核心定位。它提供桌面端和本地 HTTP 閘道，支援多協議端點和帳號池排程，幫助你快速上手本地反代並避免常見設定錯誤。","tags":["入門","概念","本地閘道","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),l={name:"zh-tw/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function i(d,t,n,s,c,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="antigravity-tools-是什麼-把「帳號-協議」做成本地-ai-閘道" tabindex="-1">Antigravity Tools 是什麼：把「帳號 + 協議」做成本地 AI 閘道 <a class="header-anchor" href="#antigravity-tools-是什麼-把「帳號-協議」做成本地-ai-閘道" aria-label="Permalink to &quot;Antigravity Tools 是什麼：把「帳號 + 協議」做成本地 AI 閘道&quot;">​</a></h1><p>很多 AI 客戶端/SDK 的接入門檻，不在「會不會呼叫 API」，而在「你到底要對接哪家協議、怎麼管理多個帳號、怎麼讓失敗自動恢復」。Antigravity Tools 試圖把這三件事，收斂成一個本地閘道。</p><h2 id="什麼是-antigravity-tools" tabindex="-1">什麼是 Antigravity Tools？ <a class="header-anchor" href="#什麼是-antigravity-tools" aria-label="Permalink to &quot;什麼是 Antigravity Tools？&quot;">​</a></h2><p><strong>Antigravity Tools</strong> 是一個桌面應用程式：你在 GUI 裡管理帳號與設定，它在本機啟動一個 HTTP 反代服務，把不同廠商/協議的請求統一轉發到上游，並把回應再轉換回客戶端熟悉的格式。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>說清楚 Antigravity Tools 解決的是什麼問題（以及它不解決什麼）</li><li>認清它的核心組成：GUI、帳號池、HTTP 反代閘道、協議適配</li><li>了解預設安全邊界（127.0.0.1、埠、驗證模式）以及什麼情況下需要改</li><li>知道下一步該去哪一章：安裝、新增帳號、啟動反代、接入客戶端</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能遇到過這些麻煩：</p><ul><li>同一個客戶端要支援 OpenAI/Anthropic/Gemini 三種協議，設定經常寫亂</li><li>有多個帳號，但切換、輪換、限流重試都靠手動</li><li>請求失敗時，你只能盯日誌猜是「帳號失效」還是「上游限流/容量耗盡」</li></ul><p>Antigravity Tools 的目標是把我們把這些「邊角工作」做進一個本地閘道裡，讓你的客戶端/SDK 盡量只關心一件事：把請求發到本地。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>你可以把它理解成一套本地的「AI 排程閘道」，由三層組成：</p><ol><li>GUI（桌面應用程式）</li></ol><ul><li>負責讓你管理帳號、設定、監控與統計。</li><li>主頁面包含：Dashboard、Accounts、API Proxy、Monitor、Token Stats、Settings。</li></ul><ol start="2"><li>HTTP 反代服務（Axum Server）</li></ol><ul><li>負責對外暴露多個協議的端點，並把請求轉交給對應 handler。</li><li>反代服務會掛載驗證、中介軟體監控、CORS、Trace 等層。</li></ul><ol start="3"><li>帳號池與排程（TokenManager 等）</li></ol><ul><li>負責從本地帳號池中挑選可用帳號，必要時刷新 token、做輪換與自癒。</li></ul><div class="info custom-block"><p class="custom-block-title">「本地閘道」是什麼意思？</p><p>這裡的「本地」是字面意思：服務跑在你自己的機器上，你的客戶端（Claude Code、OpenAI SDK、各類第三方客戶端）把 Base URL 指向 <code>http://127.0.0.1:&lt;port&gt;</code>，請求先到本機，再由 Antigravity Tools 轉發到上游。</p></div><h2 id="它對外提供哪些端點" tabindex="-1">它對外提供哪些端點 <a class="header-anchor" href="#它對外提供哪些端點" aria-label="Permalink to &quot;它對外提供哪些端點&quot;">​</a></h2><p>反代服務在一個 Router 裡註冊了多套協議端點，你可以先記住這幾個「入口」：</p><ul><li>OpenAI 相容：<code>/v1/chat/completions</code>、<code>/v1/completions</code>、<code>/v1/responses</code>、<code>/v1/models</code></li><li>Anthropic 相容：<code>/v1/messages</code>、<code>/v1/messages/count_tokens</code></li><li>Gemini 原生：<code>/v1beta/models</code>、<code>/v1beta/models/:model</code>、<code>/v1beta/models/:model/countTokens</code></li><li>健康檢查：<code>GET /healthz</code></li></ul><p>如果你的客戶端能對接其中任意一種協議，理論上都可以透過「改 Base URL」的方式，把請求導到這個本地閘道。</p><h2 id="預設安全邊界-別跳過" tabindex="-1">預設安全邊界（別跳過） <a class="header-anchor" href="#預設安全邊界-別跳過" aria-label="Permalink to &quot;預設安全邊界（別跳過）&quot;">​</a></h2><p>這類「本地反代」最大的坑，往往不是功能不夠，而是你不小心把它暴露出去了。</p><p>先記住幾條預設值（都來自預設設定）：</p><ul><li>預設埠：<code>8045</code></li><li>預設僅本機存取：<code>allow_lan_access=false</code>，監聽位址為 <code>127.0.0.1</code></li><li>預設驗證模式：<code>auth_mode=off</code>（不要求客戶端帶 key）</li><li>預設會產生一個 <code>sk-...</code> 形式的 <code>api_key</code>（供你在需要驗證時開啟）</li></ul><div class="warning custom-block"><p class="custom-block-title">什麼時候必須開啟驗證？</p><p>只要你開啟了區域網路存取（<code>allow_lan_access=true</code>，監聽位址變為 <code>0.0.0.0</code>），就應該同時啟用驗證，並把 API Key 當作密碼管理。</p></div><h2 id="什麼時候用-antigravity-tools" tabindex="-1">什麼時候用 Antigravity Tools <a class="header-anchor" href="#什麼時候用-antigravity-tools" aria-label="Permalink to &quot;什麼時候用 Antigravity Tools&quot;">​</a></h2><p>它更適合這類場景：</p><ul><li>你有多個 AI 客戶端/SDK，希望統一走一個 Base URL</li><li>你需要把不同協議（OpenAI/Anthropic/Gemini）收斂到同一套「本地出口」</li><li>你有多個帳號，希望由系統負責輪換與穩定性處理</li></ul><p>如果你只想「寫兩行程式直接呼叫官方 API」，並且帳號/協議都很固定，那它可能有點重。</p><h2 id="跟我做-先建立一個正確的使用順序" tabindex="-1">跟我做：先建立一個正確的使用順序 <a class="header-anchor" href="#跟我做-先建立一個正確的使用順序" aria-label="Permalink to &quot;跟我做：先建立一個正確的使用順序&quot;">​</a></h2><p>這節課不教你細節設定，只把主線順序先對齊，避免你跳著用導致卡住：</p><h3 id="第-1-步-先安裝再啟動" tabindex="-1">第 1 步：先安裝再啟動 <a class="header-anchor" href="#第-1-步-先安裝再啟動" aria-label="Permalink to &quot;第 1 步：先安裝再啟動&quot;">​</a></h3><p><strong>為什麼</strong> 桌面端負責帳號管理與啟動反代服務，沒有它，後續的 OAuth/反代都無從談起。</p><p>去下一章按 README 的安裝方式完成安裝。</p><p><strong>你應該看到</strong>：你能打開 Antigravity Tools，並看到 Dashboard 頁面。</p><h3 id="第-2-步-新增至少一個帳號" tabindex="-1">第 2 步：新增至少一個帳號 <a class="header-anchor" href="#第-2-步-新增至少一個帳號" aria-label="Permalink to &quot;第 2 步：新增至少一個帳號&quot;">​</a></h3><p><strong>為什麼</strong> 反代服務需要從帳號池裡拿到可用身份去向上游發請求；沒有帳號，閘道也無法「代替你呼叫」。</p><p>去「新增帳號」那一章，按 OAuth 或 Refresh Token 流程把帳號加進來。</p><p><strong>你應該看到</strong>：Accounts 頁面裡出現你的帳號，並能看到配額/狀態資訊。</p><h3 id="第-3-步-啟動-api-proxy-並用-healthz-做最小驗證" tabindex="-1">第 3 步：啟動 API Proxy，並用 /healthz 做最小驗證 <a class="header-anchor" href="#第-3-步-啟動-api-proxy-並用-healthz-做最小驗證" aria-label="Permalink to &quot;第 3 步：啟動 API Proxy，並用 /healthz 做最小驗證&quot;">​</a></h3><p><strong>為什麼</strong> 先用 <code>GET /healthz</code> 驗證「本地服務在跑」，再去接入客戶端，排障會簡單很多。</p><p>去「啟動本地反代並接入第一個客戶端」那一章完成閉環。</p><p><strong>你應該看到</strong>：你的客戶端/SDK 能透過本地 Base URL 成功拿到回應。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場景</th><th>你可能會怎麼做（❌）</th><th>推薦做法（✓）</th></tr></thead><tbody><tr><td>想讓手機/另一台電腦存取</td><td>直接打開 <code>allow_lan_access=true</code> 但不設驗證</td><td>同時啟用驗證，並先在區域網路裡驗證 <code>GET /healthz</code></td></tr><tr><td>客戶端報 404</td><td>只改 host/port，不管客戶端如何拼接 <code>/v1</code></td><td>先確認客戶端的 base_url 拼接策略，再決定是否需要帶 <code>/v1</code> 前綴</td></tr><tr><td>一上來就排 Claude Code</td><td>直接接入複雜客戶端，失敗後不知道從哪查</td><td>先跑通最小閉環：啟動 Proxy -&gt; <code>GET /healthz</code> -&gt; 再接入客戶端</td></tr></tbody></table><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Antigravity Tools 的定位是「桌面端 + 本地 HTTP 反代閘道」：GUI 管理，Axum 提供多協議端點</li><li>你需要把它當作一個本地基礎設施：先安裝、再加帳號、再啟動 Proxy、最後接入客戶端</li><li>預設只監聽 <code>127.0.0.1:8045</code>，如果要暴露到區域網路，務必同時啟用驗證</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們把安裝這一步走完：<strong><a href="./../installation/">安裝與升級：桌面端最佳安裝路徑</a></strong>。</p><p>你會學到：</p><ul><li>README 裡列出的幾種安裝方式（以及優先級）</li><li>升級入口與常見系統攔截的處理方式</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>產品定位（本地 AI 中轉站/協議鴻溝）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>Router 端點總覽（OpenAI/Claude/Gemini/healthz）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>預設埠/預設僅本機/預設 key 與 bind address 邏輯</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>GUI 頁面路由結構（Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>關鍵預設值</strong>：</p><ul><li><code>ProxyConfig.port = 8045</code>：反代服務預設埠</li><li><code>ProxyConfig.allow_lan_access = false</code>：預設僅本機存取</li><li><code>ProxyAuthMode::default() = off</code>：預設不要求驗證</li></ul></details>',55)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
